/**
 * Screen 3 — Live roundtable via WebSocket.
 *
 * Handshake: { session_config, prompt: sessionConfig.optimized_prompt, history: [] }
 *
 * WS does not stream Perplexity audit in v2; audit is merged server-side before synthesis.
 * Perplexity seat accent: #20808D (True Turquoise — brand); see `constants/modelColors.js`.
 *
 * Figma frame: 03-Session-View
 */

import React, { useCallback, useEffect, useMemo, useRef, useState } from "react";
import { MODEL_HEX } from "../constants/modelColors";
import ModelBubble from "./common/ModelBubble";
import TakeFurther from "./TakeFurther";

const DEFAULT_HTTP = "http://localhost:8000";

/** Browser WebSocket has no configurable open timeout; guard hung connects. */
const WS_CONNECT_TIMEOUT_MS = 120_000;

/** App-level keep-alive (some proxies idle-timeout unidirectional streams). */
const WS_KEEPALIVE_INTERVAL_MS = 30_000;

function wsUrlFromApiBase() {
  const base = process.env.REACT_APP_API_URL || DEFAULT_HTTP;
  try {
    const u = new URL(base);
    u.protocol = u.protocol === "https:" ? "wss:" : "ws:";
    u.pathname = "/ws/session";
    u.search = "";
    u.hash = "";
    return u.toString();
  } catch {
    return "ws://localhost:8000/ws/session";
  }
}

/** @typedef {'claude_r1' | 'gemini_r1' | 'gpt_r1' | 'synthesis' | 'idle'} StreamPhase */

function timestamp() {
  return new Date().toLocaleTimeString("en-GB", { hour: "2-digit", minute: "2-digit", second: "2-digit" });
}

function buildTranscriptDict(sessionConfig, prompt, claudeR1, geminiR1, gptR1, synthesisText) {
  const messages = [
    { role: "user", sender: "You", content: prompt, timestamp: timestamp() },
    {
      role: "assistant",
      sender: "Claude",
      content: claudeR1,
      round: "round1",
      timestamp: timestamp(),
    },
    {
      role: "assistant",
      sender: "Gemini",
      content: geminiR1,
      round: "round1",
      timestamp: timestamp(),
    },
    {
      role: "assistant",
      sender: "GPT",
      content: gptR1,
      round: "round1",
      timestamp: timestamp(),
    },
    {
      role: "assistant",
      sender: "Claude",
      content: synthesisText,
      round: "synthesis",
      timestamp: timestamp(),
    },
  ];
  return {
    messages,
    session_config: sessionConfig,
    intake_summary: sessionConfig?.intake_summary ?? null,
  };
}

/** Shown when model_complete arrived but no tokens were received (typical: dropped connection). */
function bubbleBody(text, modelComplete) {
  if (modelComplete && !(text || "").trim()) {
    return "Response interrupted — connection lost";
  }
  return text;
}

/**
 * @param {Object} props
 * @param {Object} props.sessionConfig
 * @param {function} [props.onSynthesisComplete] — (synthesisMarkdown: string) => void
 */
function SessionView({ sessionConfig, onSynthesisComplete }) {
  const onSynthesisCompleteRef = useRef(onSynthesisComplete);
  useEffect(() => {
    onSynthesisCompleteRef.current = onSynthesisComplete;
  }, [onSynthesisComplete]);

  const [wsError, setWsError] = useState(null);
  const [streamError, setStreamError] = useState(null);

  const [claudeR1, setClaudeR1] = useState("");
  const [geminiR1, setGeminiR1] = useState("");
  const [gptR1, setGptR1] = useState("");

  const [claudeR1Complete, setClaudeR1Complete] = useState(false);
  const [geminiR1Complete, setGeminiR1Complete] = useState(false);
  const [gptR1Complete, setGptR1Complete] = useState(false);

  const [synthesisText, setSynthesisText] = useState("");
  const [synthesisStreaming, setSynthesisStreaming] = useState(false);
  const [synthesisFinal, setSynthesisFinal] = useState(false);

  const [sessionComplete, setSessionComplete] = useState(false);

  const phaseRef = useRef(/** @type {StreamPhase} */ ("claude_r1"));

  const prompt = sessionConfig?.optimized_prompt ?? "";

  const transcriptForExport = useMemo(
    () => buildTranscriptDict(sessionConfig, prompt, claudeR1, geminiR1, gptR1, synthesisText),
    [sessionConfig, prompt, claudeR1, geminiR1, gptR1, synthesisText]
  );

  const appendToken = useCallback((sender, token) => {
    const phase = phaseRef.current;
    if (!token) return;

    if (phase === "claude_r1" && sender === "Claude") {
      setClaudeR1((prev) => prev + token);
      return;
    }
    if (phase === "gemini_r1" && sender === "Gemini") {
      setGeminiR1((prev) => prev + token);
      return;
    }
    if (phase === "gpt_r1" && sender === "GPT") {
      setGptR1((prev) => prev + token);
      return;
    }
    if (phase === "synthesis" && sender === "Claude") {
      setSynthesisText((prev) => prev + token);
      setSynthesisStreaming(true);
    }
  }, []);

  const handleModelComplete = useCallback((sender) => {
    if (phaseRef.current === "claude_r1" && sender === "Claude") {
      setClaudeR1Complete(true);
      phaseRef.current = "gemini_r1";
      return;
    }
    if (phaseRef.current === "gemini_r1" && sender === "Gemini") {
      setGeminiR1Complete(true);
      phaseRef.current = "gpt_r1";
      return;
    }
    if (phaseRef.current === "gpt_r1" && sender === "GPT") {
      setGptR1Complete(true);
      phaseRef.current = "synthesis";
    }
  }, []);

  useEffect(() => {
    if (!sessionConfig || typeof prompt !== "string" || !prompt.trim()) {
      setWsError("Missing session configuration or optimized prompt.");
      return;
    }

    phaseRef.current = "claude_r1";
    setWsError(null);
    setStreamError(null);
    setClaudeR1("");
    setGeminiR1("");
    setGptR1("");
    setClaudeR1Complete(false);
    setGeminiR1Complete(false);
    setGptR1Complete(false);
    setSynthesisText("");
    setSynthesisStreaming(false);
    setSynthesisFinal(false);
    setSessionComplete(false);

    const url = wsUrlFromApiBase();
    const ws = new WebSocket(url);

    ws.onmessage = (event) => {
      let data;
      try {
        data = JSON.parse(event.data);
      } catch {
        return;
      }

      switch (data.type) {
        case "token":
          appendToken(data.sender, data.token);
          break;
        case "model_complete":
          handleModelComplete(data.sender);
          break;
        case "synthesis_complete":
          setSynthesisText(data.content ?? "");
          setSynthesisStreaming(false);
          setSynthesisFinal(true);
          phaseRef.current = "idle";
          onSynthesisCompleteRef.current?.(data.content ?? "");
          break;
        case "session_complete":
          setSessionComplete(true);
          break;
        case "error":
          setStreamError(data.message || "Session error");
          break;
        default:
          break;
      }
    };

    ws.onopen = () => {
      ws.send(
        JSON.stringify({
          session_config: sessionConfig,
          prompt,
          history: [],
        })
      );
    };

    ws.onerror = () => {
      setWsError("WebSocket connection failed.");
    };

    return () => {
      ws.onmessage = null;
      if (ws.readyState === WebSocket.OPEN || ws.readyState === WebSocket.CONNECTING) {
        ws.close();
      }
    };
  }, [sessionConfig, prompt, appendToken, handleModelComplete]);

  const claudeR1Streaming = !claudeR1Complete;
  const geminiR1Streaming = claudeR1Complete && !geminiR1Complete;
  const gptR1Streaming = geminiR1Complete && !gptR1Complete;

  const showGeminiBubble = claudeR1Complete || geminiR1.length > 0;
  const showGptBubble = geminiR1Complete || gptR1.length > 0;

  return (
    <div className="min-h-screen bg-bg text-text-primary">
      <header className="border-b border-border px-4 py-4 sm:px-6">
        <div className="mx-auto max-w-3xl">
          <h1 className="text-lg font-semibold">Roundtable</h1>
          {sessionConfig?.session_title && (
            <p className="mt-0.5 text-sm text-text-secondary">{sessionConfig.session_title}</p>
          )}
        </div>
      </header>

      <div className="mx-auto max-w-3xl space-y-6 px-4 py-6 sm:px-6">
        {(wsError || streamError) && (
          <p className="text-sm text-red-400" role="alert">
            {wsError || streamError}
          </p>
        )}

        <section aria-label="Session prompt">
          <h2 className="mb-2 text-xs font-semibold uppercase tracking-wide text-text-secondary">
            Your prompt
          </h2>
          <div className="rounded-lg border border-border bg-surface px-4 py-3 text-sm leading-relaxed text-text-primary whitespace-pre-wrap">
            {prompt || "—"}
          </div>
        </section>

        <section aria-label="Model responses" className="space-y-4">
          <h2 className="text-xs font-semibold uppercase tracking-wide text-text-secondary">
            Transcript
          </h2>

          <ModelBubble
            sender="Claude"
            content={claudeR1}
            isStreaming={claudeR1Streaming}
            round="round1"
            complete={claudeR1Complete}
          />

          {showGeminiBubble && (
            <ModelBubble
              sender="Gemini"
              content={geminiR1}
              isStreaming={geminiR1Streaming}
              round="round1"
              complete={geminiR1Complete}
            />
          )}

          {showGptBubble && (
            <ModelBubble
              sender="GPT"
              content={gptR1}
              isStreaming={gptR1Streaming}
              round="round1"
              complete={gptR1Complete}
            />
          )}

          {gptR1Complete && (
            <div
              className="max-w-[min(100%,40rem)] rounded-lg border border-border bg-surface px-4 py-3 border-l-4 border-l-perplexity"
              aria-label="Perplexity audit seat"
            >
              <div
                className="mb-2 text-xs font-semibold uppercase tracking-wide"
                style={{ color: MODEL_HEX.Perplexity }}
              >
                Perplexity
                <span className="font-normal normal-case text-text-secondary"> · fact-check</span>
              </div>
              <p className="text-sm leading-relaxed text-text-secondary">
                Live audit stream is not wired in v2 WebSocket sessions; findings are still folded into
                synthesis on the server. v2.1 will stream the audit here (True Turquoise accent).
              </p>
            </div>
          )}
        </section>

        {(synthesisStreaming || synthesisFinal || synthesisText.length > 0) && (
          <section
            aria-label="Synthesis"
            className="border-t border-border pt-6"
          >
            <h2 className="mb-3 text-sm font-semibold text-text-primary">Synthesis</h2>
            <div className="rounded-lg border border-border border-l-4 border-l-claude bg-surface px-4 py-3">
              <div className="mb-2 text-xs font-semibold uppercase tracking-wide text-claude">
                Claude
                <span className="font-normal text-text-secondary"> · final deliverable</span>
              </div>
              <div className="whitespace-pre-wrap break-words text-[0.9375rem] leading-relaxed text-text-primary">
                {synthesisText}
                {synthesisStreaming && !synthesisFinal ? (
                  <span
                    className="ml-0.5 inline-block h-[1em] w-2 animate-pulse align-[-0.125em] bg-border-focus"
                    aria-hidden
                  />
                ) : null}
                {synthesisFinal ? (
                  <span className="ml-2 text-xs text-text-secondary" aria-label="Complete">
                    ✓
                  </span>
                ) : null}
              </div>
            </div>
          </section>
        )}

        {sessionComplete && (
          <TakeFurther sessionConfig={sessionConfig} transcript={transcriptForExport} />
        )}
      </div>
    </div>
  );
}

export default SessionView;
